#include <stdio.h>
#include <math.h>
typedef struct{float x,y,z;}V;
V vsub(V a,V b){return(V){a.x-b.x,a.y-b.y,a.z-b.z};}
V vadd(V a,V b){return(V){a.x+b.x,a.y+b.y,a.z+b.z};}
V vmul(V v,float s){return(V){v.x*s,v.y*s,v.z*s};}
float vdot(V a,V b){return a.x*b.x+a.y*b.y+a.z*b.z;}
float vlen(V v){return sqrtf(vdot(v,v));}
V vnorm(V v){float l=vlen(v);return(V){v.x/l,v.y/l,v.z/l};}
float sph(V ro,V rd,V c,float r){
  V oc=vsub(ro,c);
  double a=(double)vdot(rd,rd),b=2.0*vdot(oc,rd),co=vdot(oc,oc)-r*r;
  double disc=b*b-4.0*a*co;
  if(disc<0)return-1;
  double sq=sqrt(disc);
  float t=(float)((-b-sq)/(2.0*a));
  if(t<1e-3f){t=(float)((-b+sq)/(2.0*a));if(t<1e-3f)return-1;}
  return t;
}
int main(){
  int W=800,H=600;V sc={0,-.5f,-5};float sr=1;
  V L=vnorm((V){1,1,-1});
  fprintf(stderr,"Creating high-resolution image: %dx%d\n",W,H);
  fprintf(stderr,"This will be downsampled with ffmpeg after rendering\n");
  fprintf(stderr,"Rendering high-resolution image...\n");
  FILE*f=fopen("image.ppm","w");fprintf(f,"P3\n%d %d\n255\n",W,H);
  for(int row=0;row<H;row++){
    fprintf(stderr,"Progress: %.1f%%\n",(double)((float)row*100.f/600.f));
    for(int col=0;col<W;col++){
      V rd=vnorm((V){2.666667f*(col/799.f)-1.333333f,1.f-2.f*(row/599.f),-1.f});
      V ro={0,0,0};
      float ts=sph(ro,rd,sc,sr);
      float tg=-1;
      if(fabsf(rd.y)>=1e-4f){tg=-1.5f/rd.y;if(tg<1e-3f)tg=-1;}
      V color;
      if(ts>1e-3f&&(tg<1e-3f||ts<tg)){
        V hp=vadd(ro,vmul(rd,ts));V n=vnorm(vsub(hp,sc));
        float d=vdot(n,L);if(d<0)d=0;float b=.2f+.8f*d;
        float sh=sph(vadd(hp,vmul(n,.001f)),L,sc,sr);
        if(sh>0)b=.2f;
        color=(V){b,.2f*b,.2f*b};
      }else if(tg>1e-3f){
        V hp=vadd(ro,vmul(rd,tg));V n={0,1,0};
        float d=vdot(n,L);if(d<0)d=0;float b=.2f+.8f*d;
        float sh=sph(vadd(hp,vmul(n,.001f)),L,sc,sr);
        if(sh>0)b=.2f;
        int ix=(int)floorf(hp.x),iz=(int)floorf(hp.z);
        float ck=((ix+iz)&1)?.4f:.9f;
        color=(V){ck*b,ck*b,ck*b};
      }else{
        float t=.5f*(rd.y+1.f);
        color=(V){1.f-.5f*t,1.f-.3f*t,1.f};
      }
      fprintf(f,"%d %d %d\n",(int)(color.x*255.99f),(int)(color.y*255.99f),(int)(color.z*255.99f));
    }
  }
  fclose(f);
  fprintf(stderr,"Rendering complete\n");
  fprintf(stderr,"Wrote image to %s\n","image.ppm");
  fprintf(stderr,"Done.\n");
  return 0;
}
CEOF
